'use strict';
class ToolPreview{
static#instance=null;
static#TOOLTIP_ID='tool-preview-tip';
static#CONTAINER_SELECTOR='[data-tool-preview]';
static#CARD_SELECTOR='[data-tool-preview] article';
#tooltip;#activeCard=null;#hideTimeout=null;#abortController=new AbortController();
constructor(){
this.#tooltip=document.createElement('div');
this.#tooltip.id=ToolPreview.#TOOLTIP_ID;
this.#tooltip.className='tool-preview';
this.#tooltip.setAttribute('role','tooltip');
this.#tooltip.hidden=true;
(document.getElementById('main-content')??document.body).appendChild(this.#tooltip);
this.#bind();}
static init(){
if(ToolPreview.#instance)return ToolPreview.#instance;
if(!matchMedia('(hover: hover) and (pointer: fine)').matches)return null;
if(!document.querySelector(ToolPreview.#CONTAINER_SELECTOR))return null;
return(ToolPreview.#instance=new ToolPreview());}
destroy(){
clearTimeout(this.#hideTimeout);
this.#abortController.abort();
this.#tooltip.remove();
if(window.NT)NT.style.removeRule('tool-preview-pos');
ToolPreview.#instance=null;}#bind(){
const{signal}=this.#abortController;
document.addEventListener('pointerover',this.#handlePointerOver,{signal});
document.addEventListener('pointerout',this.#handlePointerOut,{signal});
document.addEventListener('focusin',this.#handleFocusIn,{signal});
document.addEventListener('focusout',this.#handleFocusOut,{signal});
document.addEventListener('keydown',this.#handleEscape,{signal});
window.addEventListener('scroll',this.#handleScroll,{signal,passive:true});}
static#conditionLabel(raw){
const map={'new':'New','good':'Good','fair':'Fair','poor':'Poor'};
return map[raw?.toLowerCase()]??raw??'';}
static#cardFrom(el){
return el?.closest?.(ToolPreview.#CARD_SELECTOR);}#show(card){
const condition=card.dataset.condition;
const owner=card.dataset.owner;
const deposit=card.dataset.deposit;
if(!condition&&!owner&&!deposit)return;
clearTimeout(this.#hideTimeout);
this.#tooltip.replaceChildren();
if(condition){
const span=document.createElement('span');
span.dataset.condition=condition.toLowerCase();
span.textContent=ToolPreview.#conditionLabel(condition);
this.#tooltip.appendChild(span);}
if(deposit){
const span=document.createElement('span');
const icon=document.createElement('i');
icon.className='fa-solid fa-shield-halved';
icon.setAttribute('aria-hidden','true');
span.append(icon,` $${deposit} deposit`);
this.#tooltip.appendChild(span);}
if(owner){
const span=document.createElement('span');
span.textContent=owner;
this.#tooltip.appendChild(span);}
this.#tooltip.hidden=false;
card.setAttribute('aria-describedby',ToolPreview.#TOOLTIP_ID);
this.#activeCard=card;
this.#position(card);}#hide(){
const card=this.#activeCard;
this.#hideTimeout=setTimeout(()=>{
this.#tooltip.hidden=true;
if(card?.getAttribute('aria-describedby')===ToolPreview.#TOOLTIP_ID){
card.removeAttribute('aria-describedby');}
this.#activeCard=null;
if(window.NT)NT.style.removeRule('tool-preview-pos');},80);}#position(card){
const rect=card.getBoundingClientRect();
const centerX=rect.left+rect.width/2+window.scrollX;
const above=rect.top>50;
const top=above
?rect.top+window.scrollY-8
:rect.bottom+window.scrollY+8;
if(window.NT){
NT.style.setRule('tool-preview-pos','.tool-preview',
`left:${centerX}px;top:${top}px;transform:${above ? 'translate(-50%,-100%)' : 'translateX(-50%)'}`);}}#handlePointerOver=(e)=>{
if(e.pointerType==='touch')return;
const card=ToolPreview.#cardFrom(e.target);
if(card&&card!==this.#activeCard)this.#show(card);};#handlePointerOut=(e)=>{
if(e.pointerType==='touch')return;
const card=ToolPreview.#cardFrom(e.target);
if(!card||card!==this.#activeCard)return;
const related=ToolPreview.#cardFrom(e.relatedTarget);
if(related!==card)this.#hide();};#handleFocusIn=(e)=>{
const card=ToolPreview.#cardFrom(e.target);
if(card)this.#show(card);};#handleFocusOut=(e)=>{
const card=ToolPreview.#cardFrom(e.target);
if(card&&card===this.#activeCard)this.#hide();};#handleEscape=(e)=>{
if(e.key==='Escape'&&this.#activeCard){
this.#tooltip.hidden=true;
if(this.#activeCard.getAttribute('aria-describedby')===ToolPreview.#TOOLTIP_ID){
this.#activeCard.removeAttribute('aria-describedby');}
this.#activeCard=null;
if(window.NT)NT.style.removeRule('tool-preview-pos');}};#handleScroll=()=>{
if(this.#activeCard)this.#position(this.#activeCard);};}
requestAnimationFrame(()=>ToolPreview.init());